const alertas = document.querySelectorAll('.alerta--exito');

if(alertas.length > 0){
    setTimeout(() => {
        alertas.forEach(alerta => {
            alerta.style.transition = 'opacity 500ms ease';
            alerta.style.opacity = '0';

                setTimeout(() =>{
                    alerta.remove();
                }, 500);
        });
    },3000);

}

//BOTONES DEL SIDEBAR
const toggleSidebar = document.querySelectorAll('.sidebar__toggle');
    if(toggleSidebar.length > 0){
        toggleSidebar.forEach(toggle => {
            toggle.addEventListener('click', function(e){
            e.preventDefault();
            
            const grupo = this.closest('.sidebar__grupo');
                  grupo.classList.toggle('sidebar__grupo--abierto');
            });          
        });
    }

//BUSCADOR DE USUARIOS
const buscador = document.querySelector('#buscarUsuarios');
const filas = document.querySelectorAll('.usuario-fila');

if(buscador){

    buscador.addEventListener('input', e => {

        const texto = e.target.value.toLowerCase();

        filas.forEach(fila => {

            const contenido = fila.textContent.toLowerCase();

            if(contenido.includes(texto)) {
                fila.style.display = 'grid';
            } else {
                fila.style.display = 'none';
            }

        });

    });

}

    //BUSCADOR DE CLIENTES
    const btnBuscar = document.getElementById('#btnBuscarClientes');
    const btnLimpiar = document.getElementById('#btnLimpiarFiltros');

    btnBuscar.addEventListener('click', buscarClientes);
    btnLimpiar.addEventListener('click', LimpiarFiltros);

    async function buscarClientes() {
        const datos = {
            buscar:    document.getElementById('buscar').value.trim(),
            vendedor:  document.getElementById('vendedor').value,
            estado:    document.getElementById('estado').value,
            saldos:    document.getElementById('saldos').value,
            localidad: document.getElementById('localidad').value
        }; 

        try {
            const respuesta = await fetch('/api/clientes/buscar', {
                method:  'POST',
                headers: { 'Content-Type': 'application/json' },
                body:    JSON.stringify(datos)
            });

            const clientes = await respuesta.json();
            renderizarClientes(clientes);

        } catch (error) {
            console.error('Error al buscar clientes:', error);
        }
    }

    function limpiarFiltros() {
        document.getElementById('buscar').value    = '';
        document.getElementById('vendedor').value  = '';
        document.getElementById('estado').value    = '';
        document.getElementById('saldos').value    = '';
        document.getElementById('localidad').value = '';
        buscarClientes(); // vuelve a traer todos
    }

    function renderClientes(clientes){

    const tabla = document.querySelector('.clientes__tabla');

    const filas = clientes.map(cliente => {

        return `
        <div class="fila grid-7">
            <span>${cliente.name}</span>
            <span>${cliente.cuit}</span>
            <span>${cliente.province}</span>
            <span>${cliente.seller_id}</span>
            <span>${cliente.price_list_id}</span>
            <span class="${cliente.active == 1 ? 'estado--completado' : 'estado--cancelado'}">
                ${cliente.active == 1 ? 'Activo' : 'Inactivo'}
            </span>
            <div class="acciones--tabla">
                <a href="/admin/clientes/ver?id=${cliente.id}"><i class="fa-solid fa-eye"></i></a>
                <a href="/admin/clientes/editar?id=${cliente.id}"><i class="fa-solid fa-pen"></i></a>
            </div>
        </div>
        `;
    }).join('');

    document.querySelectorAll('.fila').forEach(f => f.remove());

    tabla.insertAdjacentHTML('beforeend', filas);
}

     //ESTADOS
     const estados = document.querySelectorAll('.js-cambiar-estado');
      estados.forEach(el => {
        el.addEventListener('click', async function(e){
            e.preventDefault();

            const id = this.dataset.id;
            const url = `/api/clientes/estado?id=${id}`;

                try{
                    const respuesta = await fetch(url);
                const data = await respuesta.json();

                    if(data.resultado){
                        const activo = data.nuevo_estado;
                        this.textContent = activo ? 'Activo' : 'Inactivo';

                        this.classList.toggle('estado--completado', activo);
                        this.classList.toggle('estado--cancelado', !activo);
                    }
                }catch (error) {
                console.error('Error:', error);
            }
        });
    });

